import{_ as a}from"./chunks/api-keys.CiKfnKaq.js";import{_ as l,o as d,c as i,a2 as o}from"./chunks/framework.BflysNKA.js";const m=JSON.parse('{"title":"Claude Code","description":"","frontmatter":{},"headers":[],"relativePath":"tools/claude-code.md","filePath":"tools/claude-code.md","lastUpdated":1778577020000}'),s={name:"tools/claude-code.md"};function n(t,e,p,c,r,u){return d(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="claude-code" tabindex="-1">Claude Code <a class="header-anchor" href="#claude-code" aria-label="Permalink to &quot;Claude Code&quot;">​</a></h1><p>Claude Code 适合在项目目录里直接读文件、改代码和查看差异。</p><p>如果你要把 Claude Code 接到 小蓝中转站，优先看：<a href="/deploy/claude-code">Claude Code 部署</a>。</p><h2 id="为什么-claude-code-前面总会先提-git、node-js-和-npm" tabindex="-1">为什么 Claude Code 前面总会先提 Git、Node.js 和 npm <a class="header-anchor" href="#为什么-claude-code-前面总会先提-git、node-js-和-npm" aria-label="Permalink to &quot;为什么 Claude Code 前面总会先提 Git、Node.js 和 npm&quot;">​</a></h2><p>很多新手第一次看这类文档时，会觉得“我只是想用 AI，为什么还要先装 Git”。</p><p>原因其实很直接：</p><ul><li><code>Git</code> 不是为了强迫你提交代码，而是为了让 Claude Code 更稳地看懂仓库状态、差异和改动范围</li><li><code>Node.js</code> 和 <code>npm</code> 仍然是很多 CLI 工具的基础环境，后面继续装 Codex、Gemini CLI 或其他 npm CLI 时也会复用</li></ul><p>不过现在的 Claude Code 不只支持 npm。<br> 官方当前还支持原生安装脚本、Homebrew 和 WinGet，所以“想先把 Claude Code 跑起来”这件事，本身已经不一定非要先装 npm。</p><p>如果你后面还要继续折腾 Codex、Gemini CLI 或其他命令行工具，Node.js 这套环境还是建议准备好；如果你只是先想让 Claude Code 单独跑起来，原生安装脚本、Homebrew 或 WinGet 也可以先走通。</p><h2 id="claude-code-最关键的一点" tabindex="-1">Claude Code 最关键的一点 <a class="header-anchor" href="#claude-code-最关键的一点" aria-label="Permalink to &quot;Claude Code 最关键的一点&quot;">​</a></h2><p>Claude Code 填的是 Anthropic 协议根地址：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>https://xiaolan1.cn</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>不要手动补 <code>/v1</code>。<br> Claude Code 会自己继续拼 Claude 协议需要的路径。如果你手动补成 <code>https://xiaolan1.cn/v1</code>，请求很容易变成重复路径，最后看起来像“Key 失效”或“接口异常”。</p><p>第一次接入时，先记住这三项：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>ANTHROPIC_BASE_URL=https://xiaolan1.cn</span></span>
<span class="line"><span>ANTHROPIC_AUTH_TOKEN=sk-你的专属Key</span></span>
<span class="line"><span>CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY=1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>其中：</p><ul><li><code>ANTHROPIC_BASE_URL</code> 决定请求发往哪个网关</li><li><code>ANTHROPIC_AUTH_TOKEN</code> 决定请求使用哪一把 Key</li><li><code>CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY=1</code> 允许 Claude Code 向网关读取可用模型列表</li></ul><h2 id="第一次接入前先准备" tabindex="-1">第一次接入前先准备 <a class="header-anchor" href="#第一次接入前先准备" aria-label="Permalink to &quot;第一次接入前先准备&quot;">​</a></h2><ul><li>一把给 Claude Code 单独使用的 Key，例如 <code>Windows-Claude</code>（侧边栏 <strong>API 密钥</strong> 创建）</li><li>一个准备先测试的模型（从模型广场复制）</li><li>一个可用终端</li><li>Node.js、npm、Git 都已经能正常运行</li></ul><p><img src="`+a+'" alt="API 密钥页面 — 点击「创建 API 密钥」按钮"></p><p>Key 单独拆出来的意义，在于后面查日志、吊销配置和限制额度都会更清楚。</p><p>如果你还没决定装法，可以按这个思路选：</p><ul><li>想尽快开始：原生安装脚本</li><li>macOS 常用 Homebrew：Homebrew</li><li>Windows 常用系统包管理：WinGet</li><li>后面还要继续装其他 npm CLI：npm</li></ul><p>模型切换常见有三种方式：</p><ul><li><code>claude --model ...</code>：只影响这一次启动</li><li><code>/model</code>：进入 Claude Code 后切换</li><li><code>ANTHROPIC_MODEL</code>：给终端环境设置默认模型</li></ul><h2 id="第一次成功的判断" tabindex="-1">第一次成功的判断 <a class="header-anchor" href="#第一次成功的判断" aria-label="Permalink to &quot;第一次成功的判断&quot;">​</a></h2><p>第一次配置完成后，建议先在空目录里做最小测试。真正算成功时，通常要同时满足：</p><ol><li><code>claude</code> 命令能正常启动</li><li>没有跳回官方登录流程</li><li>发一句短消息后能正常返回</li><li>你确认当前读到的是 小蓝中转站 的地址和 Key</li><li>当前模型确实是你刚配置或刚切换的那一个</li></ol><p>先把这一步跑通，再切到真实项目，排障会轻松很多。</p><h2 id="继续配置" tabindex="-1">继续配置 <a class="header-anchor" href="#继续配置" aria-label="Permalink to &quot;继续配置&quot;">​</a></h2><ul><li>详细安装与环境变量写法： <a href="/deploy/claude-code">Claude Code 部署</a></li><li>还没装命令行环境： <a href="/beginner/windows">Windows 快速接入</a> / <a href="/beginner/macos">macOS 快速接入</a></li><li>想用图形界面管理配置： <a href="/tools/cc-switch">CC-Switch</a></li></ul>',31)])])}const b=l(s,[["render",n]]);export{m as __pageData,b as default};
